export class NotificationService implements INotificationService {
  constructor(
    private readonly notificationRepository: INotificationRepository,
    private readonly auditLogger: AuditLogger
  ) {}

  private getTitleForLeaveNotification(notificationType: 'leave_request' | 'leave_approval' | 'leave_rejection'): string {
    const titles = {
      leave_request: 'Leave Request Action Required',
      leave_approval: 'Leave Request Approved',
      leave_rejection: 'Leave Request Rejected'
    };
    return titles[notificationType];
  }

  private getMessageForLeaveNotification(notificationType: 'leave_request' | 'leave_approval' | 'leave_rejection', leaveRequestId: string): string {
    const messages = {
      leave_request: `A leave request (ID: ${leaveRequestId}) requires your attention.`,
      leave_approval: `Your leave request (ID: ${leaveRequestId}) has been approved.`,
      leave_rejection: `Your leave request (ID: ${leaveRequestId}) has been rejected.`
    };
    return messages[notificationType];
  }

  private sanitizeForLogging(data: any): any {
    const sanitized = { ...data };
    delete sanitized.metadata?.sensitiveData;
    return sanitized;
  }

  async sendLeaveRequestNotification(
    recipientId: string,
    leaveRequestId: string,
    notificationType: 'leave_request' | 'leave_approval' | 'leave_rejection',
    metadata?: Record<string, any>
  ): Promise<void> {
    const title = this.getTitleForLeaveNotification(notificationType);
    const message = this.getMessageForLeaveNotification(notificationType, leaveRequestId);

    const notificationData: Omit<Notification, 'id' | 'createdAt'> = {
      recipientId,
      type: notificationType,
      title,
      message,
      metadata: { ...metadata, leaveRequestId },
      isRead: false
    };

    const notification = await this.notificationRepository.create(notificationData);

    await this.auditLogger.log({
      entityType: 'notification',
      entityId: notification.id,
      action: 'create',
      oldValues: null,
      newValues: this.sanitizeForLogging(notification)
    });
  }

  async sendBalanceUpdateNotification(
    recipientId: string,
    balanceId: string,
    metadata?: Record<string, any>
  ): Promise<void> {
    const notificationData: Omit<Notification, 'id' | 'createdAt'> = {
      recipientId,
      type: 'balance_update',
      title: 'Leave Balance Updated',
      message: `Your leave balance (ID: ${balanceId}) has been updated.`,
      metadata: { ...metadata, balanceId },
      isRead: false
    };

    const notification = await this.notificationRepository.create(notificationData);

    await this.auditLogger.log({
      entityType: 'notification',
      entityId: notification.id,
      action: 'create',
      oldValues: null,
      newValues: this.sanitizeForLogging(notification)
    });
  }

  async markAsRead(notificationId: string): Promise<void> {
    const notification = await this.notificationRepository.findById(notificationId);
    if (!notification) {
      throw new Error(`Notification with ID ${notificationId} not found`);
    }

    const updatedNotification = await this.notificationRepository.update(notificationId, { 
      isRead: true, 
      readAt: new Date() 
    });

    await this.auditLogger.log({
      entityType: 'notification',
      entityId: notificationId,
      action: 'update',
      oldValues: this.sanitizeForLogging(notification),
      newValues: this.sanitizeForLogging(updatedNotification)
    });
  }

  async getUnreadNotifications(recipientId: string): Promise<Notification[]> {
    return this.notificationRepository.findUnreadByRecipient(recipientId);
  }
